//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');

}


//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {

    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면 

    switch (disGubun)
    {
        case 1:

            //내부매출부서코드팝업			
            udc_selpchDept.cfCommonPopUp(	
                scwin.udc_selpchDept_callBackFunc// 	
                ,pCode					// 화면에서의 ??? Code Element의	Value
                ,pName					// 화면에서의 ??? Name Element의	Value
                ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                ,null					// Title순서	
                ,null					// 보여주는 각 컬럼들의 폭	
                ,null					// 컬럼중에서 숨기는	컬럼 지정	
                ,null		 			// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                ,null					// 윈도우 위치 Y좌표	
                ,null					// 윈도우 위치 X좌표
                ,null                   // 중복체크여부
                ,pAllSearch             // 전체검색허용여부
                ,"부서,부서코드,부서"                // POP-UP Window Title 검색어1,2(각화면에서 변경할경우)	  										  									
            ); 

            break;	

        case 2:

            //내부매입부서코드팝업			
            udc_opntDeptCd.cfCommonPopUp(
                scwin.udc_opntDeptCd_callBackFunc// XML상의 SELECT ID	
                ,pCode					// 화면에서의 ??? Code Element의	Value
                ,pName					// 화면에서의 ??? Name Element의	Value
                ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                ,null					// Title순서	
                ,null					// 보여주는 각 컬럼들의 폭	
                ,null					// 컬럼중에서 숨기는	컬럼 지정	
                ,null		 			// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                ,null					// 윈도우 위치 Y좌표	
                ,null					// 윈도우 위치 X좌표
                ,null                   // 중복체크여부
                ,pAllSearch             // 전체검색허용여부
                ,"상대부서,상대부서코드,상대부서"                   // POP-UP Window Title 검색어1,2(각화면에서 변경할경우)	  										  									
            ); 

            break;

        case 3:

            //작업단계 코드팝업			
            udc_wrkStp.cfCommonPopUp(
                scwin.udc_wrkStp_callBackFunc	// XML상의 SELECT ID	
                ,pCode					// 화면에서의 ??? Code Element의	Value
                ,pName					// 화면에서의 ??? Name Element의	Value
                ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                ,null					// Title순서	
                ,null					// 보여주는 각 컬럼들의 폭	
                ,null					// 컬럼중에서 숨기는	컬럼 지정	
                ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                ,null					// 윈도우 위치 Y좌표	
                ,null					// 윈도우 위치 X좌표
                ,null                   // 중복체크여부
                ,pAllSearch             // 전체검색허용여부
                ,null             		// POP-UP Window Title 검색어1,2(각화면에서 변경할경우)	  										  									
            ); 

            break;


        case 10:
            //매출항목팝업			
            udc_sellItem.cfCommonPopUp(
                scwin.udc_sellItem_callBackFunc
                ,pCode.trim()
                ,pName
                ,pClose
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,pAllSearch
                ,null);

            break;

        default:
            break;
    }		

}

//-------------------------------------------------------------------------
// 상단 그리드 데이터로드 완료시
//-------------------------------------------------------------------------
scwin.ds_intertransaggr_ondataload = function () {
    let options = {
        sortIndex : "rsltsStdDt lobranNm wrkStpNm",
        sortOrder : "0 0 0"
    };

    ds_intertransaggr.multisort(options);


    spa_totalRows.setValue(ds_intertransaggr.getRowCount());


    let totalrow = ds_intertransaggr.getRowCount();
    let param = 0;

    if(totalrow == 0) {
        $c.win.alert(MSG_CM_WRN_002);
        // ed_selpchDeptCd.focus();
        ds_intertransaggr.removeAll();
        ds_intertransdetail.removeAll();
        // ds_intertransaggr.setJSON([]);
        // ds_intertransdetail.setJSON([]);
    } else {
        spa_totalRows.setValue(totalrow);
        if(ds_intertransaggr.getCellData(0, "lobranNm") != "" && cbx_detailAllYn.getValue() == "0") {
            scwin.f_InterTransDetailRetrieve(param);
        } else if (ds_intertransaggr.getCellData(0, "lobranNm") != "" && cbx_detailAllYn.getValue() != "0") {
            scwin.f_InterTransDetailRetrieve();
        }
    }


    gr_intertransaggr.setFocusedCell(0, 0);
};


